import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import SeatMap from "../components/SeatMap";
import movieService from "../services/movieService";
import showService from "../services/showService";
import seatService from "../services/seatService";
import bookingService from "../services/bookingService";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../components/Toast";

export default function MovieDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const showToast = useToast();

  const [movie, setMovie] = useState(null);
  const [shows, setShows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [currentShow, setCurrentShow] = useState(null);
  const [allSeats, setAllSeats] = useState([]);
  const [availableIds, setAvailableIds] = useState([]);
  const [selectedIds, setSelectedIds] = useState([]);
  const [seatsLoading, setSeatsLoading] = useState(false);

  useEffect(() => {
    Promise.all([movieService.getById(id), showService.getByMovie(id)])
      .then(([m, s]) => {
        setMovie(m);
        setShows(s);
      })
      .catch(() => showToast("Could not load movie", "error"))
      .finally(() => setLoading(false));
  }, [id]);

  const openSeatModal = async (show) => {
    if (!user) {
      showToast("Please login to book tickets", "error");
      setTimeout(() => navigate("/login"), 1000);
      return;
    }
    setCurrentShow(show);
    setSelectedIds([]);
    setModalOpen(true);
    setSeatsLoading(true);
    try {
      // Backend flat DTO hai — screenId directly use karo
      const screenId = show.screenId || show.screen?.id;
      console.log("screenId:", screenId, "show:", show); // debug
      const [seats, available] = await Promise.all([
        seatService.getByScreen(screenId),
        bookingService.getAvailableSeats(show.id),
      ]);
      setAllSeats(seats);
      setAvailableIds(available.map((s) => s.id));
    } catch (e) {
      console.error(e);
      showToast("Could not load seats", "error");
    } finally {
      setSeatsLoading(false);
    }
  };

  const toggleSeat = (seat) => {
    setSelectedIds((prev) =>
      prev.includes(seat.id)
        ? prev.filter((i) => i !== seat.id)
        : [...prev, seat.id],
    );
  };

  const confirmBooking = async () => {
    if (selectedIds.length === 0) {
      showToast("Select at least one seat", "error");
      return;
    }
    try {
      await bookingService.create({
        userId: user.id,
        showId: currentShow.id,
        seatIds: selectedIds,
      });
      showToast("🎉 Booking confirmed!", "success");
      setModalOpen(false);
      setTimeout(() => navigate("/bookings"), 1200);
    } catch (e) {
      showToast(e.response?.data?.message || "Booking failed", "error");
    }
  };

  if (loading)
    return (
      <div className="loading-center">
        <div className="spinner"></div>
      </div>
    );
  if (!movie)
    return (
      <div className="container">
        <div className="empty-state">
          <p>Movie not found</p>
        </div>
      </div>
    );

  const totalPrice = selectedIds.length * (currentShow?.ticketPrice || 0);

  return (
    <div className="container">
      {/* Movie Info */}
      <div className="movie-detail-hero">
        <div className="movie-poster">
          {movie.posterUrl ? (
            <img
              src={movie.posterUrl}
              alt={movie.title}
              onError={(e) => {
                e.target.style.display = "none";
                e.target.parentNode.innerHTML =
                  '<span style="font-size:6rem">🎬</span>';
              }}
            />
          ) : (
            <span style={{ fontSize: "6rem" }}>🎬</span>
          )}
        </div>
        <div className="movie-info">
          <h1>{movie.title}</h1>
          <div className="badges" style={{ marginBottom: "1rem" }}>
            {movie.genre && (
              <span className="badge badge-genre">{movie.genre}</span>
            )}
            {movie.language && (
              <span className="badge badge-lang">{movie.language}</span>
            )}
            {movie.rating && (
              <span className="badge badge-rating">⭐ {movie.rating}</span>
            )}
            {movie.durationInMinutes && (
              <span className="badge badge-dur">
                ⏱ {movie.durationInMinutes} min
              </span>
            )}
          </div>
          <p className="movie-desc">
            {movie.description || "No description available."}
          </p>
          {movie.realeseDate && (
            <p className="release-date">📅 Release: {movie.realeseDate}</p>
          )}
        </div>
      </div>

      {/* Shows */}
      <h2 className="section-title">Available Shows</h2>
      {shows.length === 0 ? (
        <div className="empty-state">
          <p>No shows available for this movie</p>
        </div>
      ) : (
        <div className="shows-list">
          {shows.map((s) => (
            <div className="show-card" key={s.id}>
              <div className="show-info">
                {/* Backend flat DTO fields use karo */}
                <h4>
                  🎥 {s.theaterName || s.screen?.theater?.name || "Theater"} —{" "}
                  {s.screenName || s.screen?.name || "Screen"}
                </h4>
                <p>
                  📅 {s.showDate} &nbsp; 🕐 {s.startTime}
                  {s.endTime ? ` - ${s.endTime}` : ""}
                </p>
                <p className="city-name">
                  {s.cityName || s.screen?.theater?.city?.name || ""}
                </p>
              </div>
              <div className="show-meta">
                <div className="price">₹{s.ticketPrice || 0}</div>
                <button
                  className="btn btn-sm btn-primary"
                  onClick={() => openSeatModal(s)}
                >
                  Select Seats
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Seat Modal */}
      {modalOpen && (
        <div
          className="modal-overlay active"
          onClick={(e) => e.target === e.currentTarget && setModalOpen(false)}
        >
          <div className="modal" style={{ maxWidth: "680px" }}>
            <button className="modal-close" onClick={() => setModalOpen(false)}>
              ×
            </button>
            <h2>
              {currentShow?.screenName || currentShow?.screen?.name || "Screen"}{" "}
              — {currentShow?.showDate} {currentShow?.startTime}
            </h2>

            {seatsLoading ? (
              <div className="loading-center">
                <div className="spinner"></div>
              </div>
            ) : allSeats.length === 0 ? (
              <div className="empty-state">
                <p>No seats found for this screen</p>
              </div>
            ) : (
              <SeatMap
                allSeats={allSeats}
                availableIds={availableIds}
                selectedIds={selectedIds}
                onToggle={toggleSeat}
              />
            )}

            {selectedIds.length > 0 && (
              <div className="booking-summary">
                <h3>Booking Summary</h3>
                <div className="summary-row">
                  <span>Seats Selected</span>
                  <span>{selectedIds.length}</span>
                </div>
                <div className="summary-row">
                  <span>Price per ticket</span>
                  <span>₹{currentShow?.ticketPrice}</span>
                </div>
                <div className="summary-row">
                  <span>Total Amount</span>
                  <span>₹{totalPrice}</span>
                </div>
              </div>
            )}

            <button
              className="btn btn-primary btn-block"
              style={{ marginTop: "1rem" }}
              disabled={selectedIds.length === 0}
              onClick={confirmBooking}
            >
              Confirm Booking
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
